import java.util.*;

public class Solution {
  public static long run(List<String> rows) {
    long hash = 1469598103934665603L;
    final int n = rows.size();
    for (int i = 0; i < n; i++) {
      String row = rows.get(i);

      // Fixed format: "src=S<digits> lat=<digits> code=<digits> ok=(yes|no)"
      final int len = row.length();
      int p = 5; // after "src=S"

      int src = 0;
      char c;
      while ((c = row.charAt(p)) != ' ') {
        src = src * 10 + (c - '0');
        p++;
      }

      p += 5; // skip " lat="
      int lat = 0;
      while ((c = row.charAt(p)) != ' ') {
        lat = lat * 10 + (c - '0');
        p++;
      }

      p += 6; // skip " code="
      int code = 0;
      while ((c = row.charAt(p)) != ' ') {
        code = code * 10 + (c - '0');
        p++;
      }

      // Remaining suffix is " ok=yes" or " ok=no"
      // After the space at current p, 'y' is at p+4 for yes.
      boolean ok = row.charAt(p + 4) == 'y';

      long v = (src & 255) + (long) lat + (long) code + (ok ? 31L : 0L);
      hash ^= (v + 1L);
      hash *= 1099511628211L;
    }
    return hash;
  }
}
